INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('培训业务专员 - 上海（实习）', '互联网 / IT', '上海', '民营企业', 120, 200, '1. 英语基础良好；2. 熟练操作Excel、Word等办公软件；3. 熟悉PS等图文设计软件、PR/AE等视频制作软件优先', '1. 性格开朗，具备优秀的沟通与协调能力；2. 做事缜密，有责任感，踏实上进；3. 学习能力与策划执行能力强，目标清晰，自驱力足', 1, '友好', '1. 负责公司培训业务相关项目的对接与支持；2. 负责培训事务相关市场宣传文件制作；3. 协助培训部负责人完成平台发展规划与执行支持；4. 完成公司安排的其他相关工作', 'OD 组织发展支持', '大专及以上', '信息安全相关专业优先，无强制专业限制', '可实习5个月，每周到岗5天，有相关实习/工作经验优先', '暑期实习', '1. 具备信息安全相关基础知识；2. 熟练使用PS、PR/AE等设计剪辑软件', '120-200元/天', '46081', '46197', 'https://www.shixiseng.com/intern/inn_atens8t7px2o?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训运营实习生 - 北京（实习）', '互联网 / IT', '北京', '民营企业', 200, 250, '1. 具备良好的文案撰写能力与设计基础；2. 具备基础的数据统计与数据分析能力；3. 可使用设计及视频剪辑软件', '1. 学习能力与主动性强，可快速适配新任务；2. 具备优秀的沟通协调能力与团队合作精神；3. 工作认真负责，注重细节，执行力强', 1, '极度友好', '1. 培训项目运营：协助线上/线下培训/认证项目落地，负责培训社群日常管理，统计分析学习数据并输出项目结果；2. 文案策划宣发：可独立完成培训项目宣发资料编辑，含课程内容、题库及配套管理制度，保障内容准确；3. 数据整理与分析：收集整理培训课前调研/课后反馈数据，维护培训记录、学员信息数据库，保障数据真实；4. 沟通协调：负责讲师、学员及支持部门的日常沟通，传递信息、协调资源；5. 课程开发：参与课程开发相关工作，如专家萃取访谈等；6. 完成其他培训运营相关工作', 'OD 组织发展支持', '本科及以上', '应用统计、人力资源管理、心理学、教育学等专业优先', '本科及以上学历在读，每周至少实习5天，可实习6个月以上', '日常实习', '1. 有培训运营、课程开发相关经验；2. 有互联网大厂实习经验', '200-250元/天', '46101', '46173', 'https://www.shixiseng.com/intern/inn_2opiko40nqzg?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训体验实习生 - 合肥（实习）', '制造', '合肥', '民营企业', 120, 180, '1. 熟练使用办公软件，特别是飞书、Excel；2. 可使用可画（Canva）等设计工具；3. 具备基础的培训项目执行与数据整理分析能力', '1. 积极主动，细致耐心；2. 具备较强的责任心和服务意识；3. 具备良好的沟通协调能力与执行力', 1, '极度友好', '1. 培训落地：协助区域内业务培训落地，创新探索培训方式，协助线上培训等形式，推动培训覆盖率；2. 制度推进：参与总部培训制度区域落地，协助规划培训，整理资源，收集需求，有效反馈；3. 数据整理：负责专员培训数据更新，整理分析报告，设计培训宣传海报；4. 服务监控：针对区域内业务场景服务达成进行日常维护管理，及时同步相关方；5. 体验落地：协助城市侧开展服务动作抽检等其他体验动作落地，保障区域工作顺利推进', 'OD 组织发展支持', '本科及以上', '人力资源、统计学、心理学等相关专业优先', '27届优先，一周出勤四天及以上，至少实习三个月', '日常实习', '1. 有汽车行业培训/用户运营相关经验；2. 有活动策划、海报设计经验', '150元/天', '46097', '46404', 'https://www.shixiseng.com/intern/inn_2afhggft8v2?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训运营实习生 - 北京（实习）', '互联网 / IT', '北京', '外资企业', 120, 200, '1. 具备良好的文字功底、图片设计能力，能够产出活动海报等，审美佳；2. 熟练使用Office办公软件；3. 具备基础的活动策划与执行能力', '1. 热爱活动策划工作，互联网冲浪达人，有脑洞，爱整活；2. 善于将创意转化为实际可行的活动方案；3. 积极主动，学习能力强，具备良好的团队合作精神', 1, '友好', '1. 根据需求参与各类线上线下学习活动策划，为活动提供新颖、有趣的创意点子；2. 根据目标，参与各类大赛活动组织运营，包括活动主题、流程设计、内容创意等；3. 跟踪活动执行过程，确保活动顺利进行，并对效果进行评估和总结', 'OD 组织发展支持', '不限', '人力资源、新闻学、传播学、广告学等相关专业优先', '可实习5个月及以上，每周能保证出勤4天以上为佳，能长期实习优先', '日常实习', '1. 有大型活动策划与执行经验；2. 有互联网大厂实习经验', '120-200元/天', '46063', '46388', 'https://www.shixiseng.com/intern/inn_hthpsedomdhv?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）'), ('培训运营实习生 - 北京（实习）', '互联网 / IT', '北京', '民营企业', 150, 250, '1. 有视频剪辑包装能力，熟悉使用摄像机，了解直播流程；2. 熟练使用PR/PS/AE/finalcut/AI等软件；3. 熟练使用Office办公软件', '1. 有责任心，细心踏实；2. 学习能力强，积极主动；3. 具备良好的执行力与细节把控能力', 1, '友好', '1. 负责日常培训的课前准备、现场实施运营、培训后的信息整理；2. 负责教学视频剪辑包装；3. 负责教学直播和课程录制支持；4. 利用社群运营，结合学习热点，完成学习内容的推广，保证用户体验；5. 负责学习平台中培训数据的录入、整理，保证数据准确性', 'OD 组织发展支持', '本科及以上', '无强制专业限制', '每周在岗5天，实习3个月以上', '日常实习', '1. 有课程运营、直播运营相关经验；2. 有互联网大厂实习经验', '150-250元/天', '46112', '46451', 'https://www.shixiseng.com/intern/inn_z4nfnzenfdjs?pcm=pc_SearchList', 'OD类', '甲方（企业自有 HR 岗）');